import{_ as p,c as r}from"./app.90a21e26.js";const n={},t=r('<h1 id="_34-\u8BB2-\u7AD9\u5728\u5DE8\u4EBA\u7684\u80A9\u8180-\u4F01\u4E1A\u7EA7\u5B9E\u9645\u6027\u80FD\u6D4B\u8BD5\u6848\u4F8B\u4E0E\u7ECF\u9A8C\u5206\u4EAB" tabindex="-1"><a class="header-anchor" href="#_34-\u8BB2-\u7AD9\u5728\u5DE8\u4EBA\u7684\u80A9\u8180-\u4F01\u4E1A\u7EA7\u5B9E\u9645\u6027\u80FD\u6D4B\u8BD5\u6848\u4F8B\u4E0E\u7ECF\u9A8C\u5206\u4EAB" aria-hidden="true">#</a> 34 \u8BB2\uFF1A\u7AD9\u5728\u5DE8\u4EBA\u7684\u80A9\u8180\uFF1A\u4F01\u4E1A\u7EA7\u5B9E\u9645\u6027\u80FD\u6D4B\u8BD5\u6848\u4F8B\u4E0E\u7ECF\u9A8C\u5206\u4EAB</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\uFF0C\u4ECA\u5929\u6211\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u7AD9\u5728\u5DE8\u4EBA\u7684\u80A9\u8180\u4E4B\u4F01\u4E1A\u7EA7\u5B9E\u9645\u6027\u80FD\u6D4B\u8BD5\u6848\u4F8B\u4E0E\u7ECF\u9A8C\u5206\u4EAB\u201D\u3002</p><p>\u5728\u524D\u9762\u7684\u56DB\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4ECB\u7ECD\u4E86\u524D\u7AEF\u6027\u80FD\u6D4B\u8BD5\u548C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u7406\u8BBA\u4E0E\u65B9\u6CD5\uFF0C\u8FD8\u5206\u4EAB\u4E86\u4F7F\u7528 LoadRunner \u5B9E\u73B0\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u8FC7\u7A0B\u3002\u6709\u4E86\u8FD9\u4E9B\u5185\u5BB9\u7684\u94FA\u57AB\uFF0C\u6211\u4ECA\u5929\u4F1A\u548C\u4F60\u804A\u804A\u4F20\u7EDF\u7684\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\u4F01\u4E1A\u5982\u4F55\u5F00\u5C55\u6027\u80FD\u6D4B\u8BD5\u5DE5\u4F5C\u3002</p><p>\u5176\u5B9E\uFF0C\u4F20\u7EDF\u7684\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\u4EA7\u54C1\u548C\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6027\u80FD\u6D4B\u8BD5\uFF0C\u5728\u539F\u7406\u548C\u6D4B\u8BD5\u65B9\u6CD5\u4E0A\u57FA\u672C\u4E00\u81F4\uFF0C\u5B83\u4EEC\u6700\u5927\u7684\u533A\u522B\u4F53\u73B0\u5728\u5E76\u53D1\u6570\u91CF\u7684\u6570\u91CF\u7EA7\u4E0A\uFF0C\u4EE5\u53CA\u4E92\u8054\u7F51\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6027\u80FD\u6D4B\u8BD5\u8FD8\u9700\u8981\u76F4\u63A5\u5728\u751F\u4EA7\u73AF\u5883\u4E0B\u8FDB\u884C\u7279\u6709\u7684\u5168\u94FE\u8DEF\u538B\u6D4B\u3002\u800C\u5168\u94FE\u8DEF\u538B\u6D4B\u5176\u5B9E\u662F\u5728\u4F20\u7EDF\u7684\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6027\u80FD\u6D4B\u8BD5\u57FA\u7840\u4E0A\uFF0C\u53C8\u8FDB\u884C\u4E86\u4E00\u4E9B\u6269\u5C55\u3002</p><p>\u6240\u4EE5\uFF0C\u5728\u6211\u770B\u6765\uFF0C\u53EA\u8981\u638C\u63E1\u4E86\u4F20\u7EDF\u7684\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6027\u80FD\u6D4B\u8BD5\u7684\u539F\u7406\u548C\u65B9\u6CD5\uFF0C\u641E\u5B9A\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6027\u80FD\u6D4B\u8BD5\u81EA\u7136\u4E0D\u5728\u8BDD\u4E0B\u3002</p><p>\u8A00\u5F52\u6B63\u4F20\uFF0C\u4F20\u7EDF\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6027\u80FD\u6D4B\u8BD5\u91CD\u70B9\u662F\u5728\u670D\u52A1\u5668\u7AEF\u3002\u4E3A\u4E86\u8FBE\u5230\u4E0D\u540C\u7684\u6D4B\u8BD5\u76EE\u6807\uFF0C\u5F80\u5F80\u4F1A\u6709\u591A\u79CD\u4E0D\u540C\u7C7B\u578B\u7684\u6027\u80FD\u6D4B\u8BD5\u3002\u4ECA\u5929\uFF0C\u6211\u5C31\u548C\u4F60\u804A\u804A\u8FD9\u5176\u4E2D\u90FD\u6709\u54EA\u4E9B\u6D4B\u8BD5\u7C7B\u578B\uFF0C\u4EE5\u53CA\u6BCF\u7C7B\u6D4B\u8BD5\u7684\u76EE\u7684\u3001\u6240\u91C7\u7528\u7684\u65B9\u6CD5\u3002</p><p>\u6240\u4EE5\uFF0C\u4ECA\u5929\u7684\u5206\u4EAB\uFF0C\u6211\u4F1A\u4ECE\u4EE5\u4E0B\u56DB\u79CD\u6D4B\u8BD5\u7C7B\u578B\u7684\u89D2\u5EA6\u5C55\u5F00\uFF1A</p><ul><li>\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\uFF1B</li><li>\u7A33\u5B9A\u6027\u6D4B\u8BD5\uFF1B</li><li>\u5E76\u53D1\u6D4B\u8BD5\uFF1B</li><li>\u5BB9\u91CF\u89C4\u5212\u6D4B\u8BD5\u3002</li></ul><p><strong>\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5</strong></p><p>\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\uFF0C\u901A\u5E38\u88AB\u79F0\u4E3A Performance Benchmark Test\uFF0C\u662F\u6BCF\u6B21\u5BF9\u5916\u53D1\u5E03\u4EA7\u54C1\u7248\u672C\u524D\u5FC5\u987B\u8981\u5B8C\u6210\u7684\u6D4B\u8BD5\u7C7B\u578B\u3002</p><p>\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\uFF0C\u4F1A\u57FA\u4E8E\u56FA\u5B9A\u7684\u786C\u4EF6\u73AF\u5883\u548C\u90E8\u7F72\u67B6\u6784\uFF08\u6BD4\u5982\u4E13\u7528\u7684\u670D\u52A1\u5668\u3001\u56FA\u5B9A\u7684\u4E13\u7528\u7F51\u7EDC\u73AF\u5883\u3001\u56FA\u5B9A\u5927\u5C0F\u7684\u96C6\u7FA4\u89C4\u6A21\u3001\u76F8\u540C\u7684\u7CFB\u7EDF\u914D\u7F6E\u3001\u76F8\u540C\u7684\u6570\u636E\u5E93\u80CC\u666F\u6570\u636E\u7B49\uFF09\uFF0C\u901A\u8FC7\u6267\u884C\u56FA\u5B9A\u7684\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u5F97\u5230\u7CFB\u7EDF\u7684\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\uFF0C\u7136\u540E\u4E0E\u4E0A\u4E00\u7248\u672C\u53D1\u5E03\u65F6\u7684\u6307\u6807\u8FDB\u884C\u5BF9\u6BD4\uFF0C\u5982\u679C\u53D1\u73B0\u6307\u6807\u6709\u201C\u6076\u5316\u201D\u7684\u8D8B\u52BF\uFF0C\u5C31\u9700\u8981\u8FDB\u4E00\u6B65\u6392\u67E5\u3002</p><p>\u5178\u578B\u7684\u201C\u6076\u5316\u201D\u8D8B\u52BF\uFF0C\u4E3B\u8981\u8868\u73B0\u5728\u4EE5\u4E0B\u51E0\u4E2A\u65B9\u9762\uFF1A</p><p>\u540C\u4E00\u4E8B\u52A1\u7684\u54CD\u5E94\u65F6\u95F4\u53D8\u6162\u4E86\u3002\u6BD4\u5982\uFF0C\u4E0A\u4E00\u7248\u672C\u4E2D\uFF0C\u7528\u6237\u767B\u5F55\u7684\u54CD\u5E94\u65F6\u95F4\u662F 2 s\uFF0C\u4F46\u662F\u5728\u6700\u65B0\u7684\u88AB\u6D4B\u7248\u672C\u4E2D\u8FD9\u4E2A\u54CD\u5E94\u65F6\u95F4\u53D8\u6210\u4E86 4 s\uFF1B \u7CFB\u7EDF\u8D44\u6E90\u7684\u5360\u7528\u7387\u53D8\u9AD8\u4E86\u3002\u6BD4\u5982\uFF0C\u4E0A\u4E00\u7248\u672C\u4E2D\uFF0C\u5E73\u5747 CPU \u5360\u7528\u7387\u662F 15%\uFF0C\u4F46\u662F\u5728\u6700\u65B0\u7684\u88AB\u6D4B\u7248\u672C\u4E2D\u5E73\u5747 CPU \u5360\u7528\u7387\u53D8\u6210\u4E86 30%\uFF1B \u7F51\u7EDC\u5E26\u5BBD\u7684\u4F7F\u7528\u91CF\u53D8\u9AD8\u4E86\u3002\u6BD4\u5982\uFF0C\u4E0A\u4E00\u7248\u672C\u4E2D\uFF0C\u53D1\u9001\u603B\u5B57\u8282\u6570\u662F 20 MB\uFF0C\u63A5\u6536\u603B\u5B57\u8282\u6570\u662F 200 MB\uFF0C\u4F46\u662F\u5728\u6700\u65B0\u7684\u88AB\u6D4B\u7248\u672C\u4E2D\u53D1\u9001\u603B\u5B57\u8282\u6570\u53D8\u6210\u4E86 25 MB\uFF0C\u63A5\u6536\u603B\u5B57\u8282\u6570\u53D8\u6210\u4E86 250 MB\u3002 \u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u8FD9\u4E9B\u201C\u6076\u5316\u201D\u8D8B\u52BF\u7684\u524D\u63D0\u662F\uFF1A\u5B8C\u5168\u76F8\u540C\u7684\u73AF\u5883\u4EE5\u53CA\u6D4B\u8BD5\u8D1F\u8F7D\u3002\u4E0D\u540C\u201C\u6076\u5316\u201D\u6307\u6807\u7684\u6392\u67E5\uFF0C\u6709\u4E0D\u540C\u7684\u65B9\u6CD5\u3002\u6211\u4EE5\u6700\u5E38\u89C1\u7684\u4E8B\u52A1\u54CD\u5E94\u65F6\u95F4\u53D8\u6162\u4E3A\u4F8B\uFF0C\u548C\u4F60\u8BF4\u660E\u4E00\u4E0B\u6392\u67E5\u65B9\u6CD5\u3002</p><p>\u5047\u8BBE\uFF0C\u901A\u8FC7\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u7684\u6BD4\u8F83\u7ED3\u679C\u5F97\u77E5\uFF0C\u7528\u6237\u767B\u5F55\u7684\u54CD\u5E94\u65F6\u95F4\u4ECE 2 s \u53D8\u6210\u4E86 4 s\u3002</p><p>\u90A3\u4E48\uFF0C\u6211\u4EEC\u9996\u5148\u8981\u505A\u7684\u662F\u9A8C\u8BC1\u5728\u5355\u7528\u6237\u7684\u60C5\u51B5\u4E0B\uFF0C\u662F\u5426\u4F1A\u51FA\u73B0\u54CD\u5E94\u65F6\u95F4\u53D8\u957F\u7684\u95EE\u9898\u3002\u5177\u4F53\u505A\u6CD5\u662F\uFF0C\u5C06\u7528\u6237\u767B\u5F55\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u5355\u72EC\u62FF\u51FA\u6765\uFF0C\u5EFA\u7ACB\u4E00\u4E2A\u5355\u7528\u6237\u8FD0\u884C\u7684\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u5E76\u6267\u884C\uFF0C\u89C2\u5BDF\u7528\u6237\u767B\u5F55\u7684\u54CD\u5E94\u65F6\u95F4\u662F\u5426\u53D8\u6162\u3002</p><p>\u5982\u679C\u53D8\u6162\u4E86\uFF0C\u5C31\u8BF4\u660E\u8FD9\u662F\u5355\u7528\u6237\u767B\u5F55\u573A\u666F\u5C31\u53EF\u91CD\u73B0\u7684\u6027\u80FD\u95EE\u9898\uFF0C\u540E\u7EED\u7684\u5904\u7406\u4E5F\u76F8\u5BF9\u7B80\u5355\u4E86\u3002\u89E3\u51B3\u65B9\u6CD5\u662F\uFF1A\u5206\u6790\u5355\u7528\u6237\u767B\u5F55\u7684\u540E\u7AEF\u65E5\u5FD7\u6587\u4EF6\uFF0C\u770B\u770B\u5B8C\u6210\u767B\u5F55\u64CD\u4F5C\u7684\u65F6\u95F4\u5177\u4F53\u90FD\u82B1\u5728\u4E86\u54EA\u4E9B\u6B65\u9AA4\u4E0A\uFF0C\u76F8\u6BD4\u4E4B\u524D\u54EA\u4E9B\u6B65\u9AA4\u82B1\u8D39\u7684\u65F6\u95F4\u53D8\u957F\u4E86\uFF0C\u6216\u8005\u662F\u591A\u51FA\u4E86\u54EA\u4E9B\u989D\u5916\u7684\u6B65\u9AA4\u3002</p><p>\u5982\u679C\u6CA1\u6709\u53D8\u6162\uFF0C\u5219\u8BF4\u660E\u6211\u4EEC\u5FC5\u987B\u5C1D\u8BD5\u5728\u6709\u538B\u529B\u7684\u60C5\u51B5\u4E0B\u91CD\u73B0\u8FD9\u4E2A\u6027\u80FD\u95EE\u9898\u3002\u4E3A\u6B64\uFF0C\u6211\u4EEC\u8981\u57FA\u4E8E\u7528\u6237\u767B\u5F55\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u6784\u5EFA\u5E76\u53D1\u6D4B\u8BD5\u7684\u573A\u666F\uFF0C\u4F46\u662F\u6211\u4EEC\u5E76\u4E0D\u6E05\u695A\u5728\u8FD9\u4E2A\u573A\u666F\u8BBE\u8BA1\u4E2D\u5230\u5E95\u5E94\u8BE5\u91C7\u7528\u591A\u5C11\u5E76\u53D1\u7528\u6237\u3001\u52A0\u5165\u591A\u957F\u7684\u601D\u8003\u65F6\u95F4\u3002\u8FD9\u65F6\uFF0C\u901A\u5E38\u7684\u505A\u6CD5\u662F\uFF0C\u76F4\u63A5\u91C7\u7528\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u4E2D\u7684\u5E76\u53D1\u7528\u6237\u6570\u548C\u601D\u8003\u65F6\u95F4\uFF0C\u53BB\u5C1D\u8BD5\u91CD\u73B0\u95EE\u9898\u3002\u5982\u679C\u65E0\u6CD5\u91CD\u73B0\uFF0C\u6211\u4EEC\u53EF\u4EE5\u9002\u5F53\u5730\u9010\u6B65\u52A0\u5927\u6D4B\u8BD5\u8D1F\u8F7D\uFF0C\u5E76\u89C2\u5BDF\u54CD\u5E94\u65F6\u95F4\u7684\u53D8\u5316\u8D8B\u52BF\u3002</p><p>\u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u5343\u4E07\u4E0D\u8981\u4F7F\u7528\u8FC7\u5927\u7684\u6D4B\u8BD5\u8D1F\u8F7D\u3002\u56E0\u4E3A\u6D4B\u8BD5\u8D1F\u8F7D\u8FC7\u5927\u7684\u8BDD\uFF0C\u7CFB\u7EDF\u8D44\u6E90\u4E5F\u4F1A\u6210\u4E3A\u6027\u80FD\u74F6\u9888\uFF0C\u4E00\u5B9A\u4F1A\u4F7F\u54CD\u5E94\u65F6\u95F4\u53D8\u957F\u3002\u4F46\u8FD9\u65F6\uFF0C\u54CD\u5E94\u65F6\u95F4\u53D8\u957F\u4E3B\u8981\u662F\u7531\u8D44\u6E90\u74F6\u9888\u9020\u6210\u7684\uFF0C\u800C\u4E0D\u662F\u4F60\u5F00\u59CB\u8981\u627E\u7684\u90A3\u4E2A\u539F\u56E0\u3002</p><p>\u5982\u679C\u6B64\u65F6\u53EF\u4EE5\u91CD\u73B0\u95EE\u9898\uFF0C\u90A3\u5C31\u53EF\u4EE5\u8FDB\u4E00\u6B65\u53BB\u5206\u6790\u5E76\u53D1\u573A\u666F\u4E0B\uFF0C\u7528\u6237\u767B\u5F55\u64CD\u4F5C\u7684\u65F6\u95F4\u5207\u7247\uFF0C\u627E\u5230\u5177\u4F53\u7684\u539F\u56E0\u3002\u5982\u679C\u6B64\u65F6\u8FD8\u662F\u4E0D\u80FD\u91CD\u73B0\u95EE\u9898\u7684\u8BDD\uFF0C\u60C5\u51B5\u5C31\u6BD4\u8F83\u590D\u6742\u4E86\uFF0C\u4E5F\u5C31\u662F\u767B\u5F55\u64CD\u4F5C\u7684\u6027\u80FD\u53EF\u80FD\u548C\u5176\u4ED6\u7684\u4E1A\u52A1\u64CD\u4F5C\u5B58\u5728\u4F9D\u8D56\uFF0C\u6216\u8005\u67D0\u79CD\u8D44\u6E90\u7ADE\u4E89\u5173\u7CFB\uFF0C\u8FD9\u5C31\u8981\u5177\u4F53\u95EE\u9898\u5177\u4F53\u5206\u6790\u4E86\u3002</p><p>\u4E00\u822C\u6765\u8BF4\uFF0C\u5F53\u5B9A\u4F4D\u5230\u6027\u80FD\u201C\u6076\u5316\u201D\u7684\u539F\u56E0\u5E76\u4FEE\u590D\u540E\uFF0C\u6211\u4EEC\u8FD8\u4F1A\u518D\u6267\u884C\u4E00\u8F6E\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\uFF0C\u4EE5\u786E\u4FDD\u7CFB\u7EDF\u5BF9\u5916\u53D1\u5E03\u524D\u7684\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u6307\u6807\u6CA1\u6709\u201C\u53D8\u574F\u201D\u3002\u53EF\u4EE5\u8BF4\uFF0C\u901A\u8FC7\u5BF9\u6BCF\u4E2A\u9884\u53D1\u5E03\u7248\u672C\u7684\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\uFF0C\u6211\u4EEC\u53EF\u4EE5\u4FDD\u8BC1\u65B0\u53D1\u5E03\u7CFB\u7EDF\u7684\u6574\u4F53\u6027\u80FD\u4E0D\u4F1A\u4E0B\u964D\uFF0C\u8FD9\u4E5F\u5C31\u662F\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u6700\u7EC8\u8981\u8FBE\u5230\u7684\u76EE\u7684\u3002</p><p>\u5F88\u591A\u5927\u578B\u7684\u4F20\u7EDF\u8F6F\u4EF6\u516C\u53F8\u90FD\u6709\u4E13\u95E8\u7684\u6027\u80FD\u6D4B\u8BD5\u56E2\u961F\uFF0C\u8FD9\u4E2A\u56E2\u961F\u4F1A\u5EFA\u7ACB\u6807\u51C6\u7684\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u573A\u666F\uFF0C\u5E76\u628A\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u7684\u7ED3\u679C\u4F5C\u4E3A\u4EA7\u54C1\u662F\u5426\u53EF\u4EE5\u53D1\u5E03\u7684\u4F9D\u636E\u4E4B\u4E00\u3002\u6BD4\u5982\uFF0C\u6211\u66FE\u5DE5\u4F5C\u8FC7\u7684 HP \u8F6F\u4EF6\uFF0C\u5C31\u7531\u6027\u80FD\u6D4B\u8BD5\u5353\u8D8A\u4E2D\u5FC3\u8D1F\u8D23\u7EF4\u62A4\u3001\u6267\u884C\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\uFF0C\u5E76\u5206\u6790\u6D4B\u8BD5\u7ED3\u679C\u3002</p><p>\u4ECE\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u7684\u8BBE\u8BA1\u89D2\u5EA6\u6765\u770B\uFF0C\u4F60\u9700\u8981\u7279\u522B\u6CE8\u610F\u4EE5\u4E0B\u4E09\u70B9\uFF1A</p><p>\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u4E2D\u865A\u62DF\u7528\u6237\u811A\u672C\u7684\u9009\u62E9\u4EE5\u53CA\u914D\u6BD4\uFF0C\u9700\u8981\u5C3D\u53EF\u80FD\u5730\u5339\u914D\u5B9E\u9645\u7684\u8D1F\u8F7D\u60C5\u51B5\uFF1B</p><p>\u603B\u4F53\u7684\u8D1F\u8F7D\u8BBE\u8BA1\u4E0D\u5B9C\u8FC7\u9AD8\uFF0C\u901A\u5E38\u88AB\u6D4B\u7CFB\u7EDF\u7684\u5404\u7C7B\u5360\u7528\u7387\u6307\u6807\u9700\u8981\u63A7\u5236\u5728 30%\u4EE5\u5185\uFF0C\u5C3D\u91CF\u907F\u514D\u7531\u4E8E\u8D44\u6E90\u74F6\u9888\u5F15\u5165\u7684\u64CD\u4F5C\u5EF6\u65F6\uFF1B</p><p>\u6BCF\u6B21\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u524D\uFF0C\u4E00\u822C\u9700\u8981\u5BF9\u7CFB\u7EDF\u8D44\u6E90\u4EE5\u53CA\u7F51\u7EDC\u8D44\u6E90\u505A\u4E00\u8F6E\u5FEB\u901F\u7684\u57FA\u51C6\u6D4B\u8BD5\uFF0C\u4EE5\u4FDD\u8BC1\u6BCF\u6B21\u88AB\u6D4B\u73AF\u5883\u7684\u4E00\u81F4\u6027\uFF0C\u540C\u65F6\u4E5F\u8981\u4FDD\u8BC1\u6570\u636E\u5E93\u7684\u6570\u636E\u91CF\u5728\u540C\u4E00\u4E2A\u7EA7\u522B\u4E0A\u3002\u603B\u4E4B\uFF0C\u4F60\u9700\u8981\u91C7\u7528\u4E00\u5207\u53EF\u80FD\u7684\u624B\u6BB5\uFF0C\u6765\u786E\u4FDD\u591A\u6B21\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u4E4B\u95F4\u7684\u73AF\u5883\u4E00\u81F4\u6027\u3002</p><p>\u7A33\u5B9A\u6027\u6D4B\u8BD5 \u7A33\u5B9A\u6027\u6D4B\u8BD5\uFF0C\u53C8\u79F0\u53EF\u9760\u6027\u6D4B\u8BD5\uFF0C\u4E3B\u8981\u662F\u901A\u8FC7\u957F\u65F6\u95F4\uFF087*24 \u5C0F\u65F6\uFF09\u6A21\u62DF\u88AB\u6D4B\u7CFB\u7EDF\u7684\u6D4B\u8BD5\u8D1F\u8F7D\uFF0C\u6765\u89C2\u5BDF\u7CFB\u7EDF\u5728\u957F\u671F\u8FD0\u884C\u8FC7\u7A0B\u4E2D\u662F\u5426\u6709\u6F5C\u5728\u7684\u95EE\u9898\u3002\u901A\u8FC7\u5BF9\u7CFB\u7EDF\u6307\u6807\u7684\u76D1\u63A7\uFF0C\u7A33\u5B9A\u6027\u6D4B\u8BD5\u53EF\u4EE5\u53D1\u73B0\u8BF8\u5982\u5185\u5B58\u6CC4\u6F0F\u3001\u8D44\u6E90\u975E\u6CD5\u5360\u7528\u7B49\u95EE\u9898\u3002</p><p>\u5F88\u591A\u4F01\u4E1A\u7EA7\u7684\u670D\u52A1\u5668\u7AEF\u4EA7\u54C1\uFF0C\u5728\u53D1\u5E03\u524D\u5F80\u5F80\u90FD\u8981\u8FDB\u884C\u7A33\u5B9A\u6027\u6D4B\u8BD5\u3002\u7A33\u5B9A\u6027\u6D4B\u8BD5\uFF0C\u901A\u5E38\u76F4\u63A5\u91C7\u7528\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u4E2D\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u4F46\u662F\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u7684\u8BBE\u8BA1\u548C\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u573A\u666F\u4F1A\u6709\u5F88\u5927\u4E0D\u540C\uFF1A</p><p>\u4E00\u822C\u662F\u91C7\u7528\u201C\u6CE2\u6D6A\u5F0F\u201D\u7684\u6D4B\u8BD5\u8D1F\u8F7D\uFF0C\u6BD4\u5982\u5148\u9010\u6E10\u52A0\u5927\u6D4B\u8BD5\u8D1F\u8F7D\uFF0C\u5728\u9AD8\u8D1F\u8F7D\u60C5\u51B5\u4E0B\u6301\u7EED 10 \u591A\u4E2A\u5C0F\u65F6\uFF0C\u7136\u540E\u518D\u9010\u6E10\u964D\u4F4E\u8D1F\u8F7D\uFF0C\u8FD9\u6837\u5C31\u6784\u6210\u4E86\u4E00\u4E2A\u201C\u6CE2\u6D6A\u201D\uFF0C\u6574\u4E2A\u7A33\u5B9A\u6027\u6D4B\u8BD5\u5C06\u7531\u5F88\u591A\u4E2A\u8FD9\u6837\u7684\u6CE2\u6D6A\u8FDE\u7EED\u7EC4\u6210\u3002</p><p>\u7A33\u5B9A\u6027\u6D4B\u8BD5\u6210\u529F\u5B8C\u6210\u7684\u6807\u5FD7\uFF0C\u4E3B\u8981\u6709\u4EE5\u4E0B\u4E09\u9879\uFF1A</p><p>\u7CFB\u7EDF\u8D44\u6E90\u7684\u6240\u6709\u76D1\u63A7\u6307\u6807\u4E0D\u5B58\u5728\u201C\u4E0D\u53EF\u9006\u8F6C\u201D\u7684\u4E0A\u5347\u8D8B\u52BF\uFF1B \u4E8B\u52A1\u7684\u54CD\u5E94\u65F6\u95F4\u4E0D\u5B58\u5728\u9010\u6E10\u53D8\u6162\u7684\u8D8B\u52BF\uFF1B \u4E8B\u52A1\u7684\u9519\u8BEF\u7387\u4E0D\u8D85\u8FC7 1%\u3002 \u5B9E\u9645\u5DE5\u7A0B\u9879\u76EE\u4E2D\uFF0C\u7531\u4E8E\u7A33\u5B9A\u6027\u6D4B\u8BD5\u6267\u884C\u7684\u65F6\u95F4\u6210\u672C\u5F88\u9AD8\uFF0C\u5F80\u5F80\u9700\u8981\u82B1\u8D39 3~7 \u5929\u7684\u65F6\u95F4\uFF0C\u6240\u4EE5\u6211\u4EEC\u4E00\u822C\u662F\u5728\u5176\u4ED6\u6240\u6709\u6D4B\u8BD5\u90FD\u5DF2\u7ECF\u5B8C\u6210\uFF0C\u5E76\u4E14\u6240\u6709\u95EE\u9898\u90FD\u5DF2\u7ECF\u4FEE\u590D\u4E4B\u540E\u624D\u5F00\u59CB\u7A33\u5B9A\u6027\u6D4B\u8BD5\u3002</p><p>\u53E6\u5916\uFF0C\u6709\u4E9B\u4F01\u4E1A\u4E3A\u4E86\u7F29\u77ED\u7A33\u5B9A\u6027\u6D4B\u8BD5\u7684\u6267\u884C\u65F6\u95F4\uFF0C\u5F80\u5F80\u8FD8\u4F1A\u91C7\u7528\u201C\u65F6\u95F4\u8F74\u538B\u7F29\u201D\u7684\u65B9\u6CD5\uFF0C\u5177\u4F53\u7684\u505A\u6CD5\u5C31\u662F\uFF1A\u5728\u52A0\u5927\u6D4B\u8BD5\u8D1F\u8F7D\u7684\u524D\u63D0\u4E0B\uFF0C\u9002\u5F53\u7F29\u77ED\u6BCF\u4E2A\u201C\u6CE2\u6D6A\u201D\u7684\u65F6\u95F4\uFF0C\u4ECE\u800C\u51CF\u5C11\u6574\u4F53\u7684\u6D4B\u8BD5\u6267\u884C\u65F6\u95F4\u3002</p><p>\u6700\u540E\uFF0C\u9700\u8981\u5F3A\u8C03\u7684\u4E00\u70B9\u662F\uFF0C\u867D\u7136\u5F88\u591A\u65F6\u5019\uFF0C\u5C24\u5176\u662F\u4EA7\u54C1\u7248\u672C\u5DF2\u7ECF\u9010\u6E10\u8D70\u5411\u6210\u719F\u671F\u65F6\uFF0C\u7A33\u5B9A\u6027\u6D4B\u8BD5\u5E76\u4E0D\u4F1A\u53D1\u73B0\u95EE\u9898\uFF0C\u4F46\u662F\u5343\u4E07\u4E0D\u8981\u5C0F\u770B\u7A33\u5B9A\u6027\u6D4B\u8BD5\u5E26\u6765\u7684\u4EF7\u503C\u3002\u56E0\u4E3A\u7A33\u5B9A\u6027\u6D4B\u8BD5\u4E00\u65E6\u53D1\u73B0\u95EE\u9898\uFF0C\u90A3\u4E48\u8FD9\u4E9B\u95EE\u9898\u90FD\u662F\u5F88\u4E25\u91CD\u800C\u4E14\u975E\u5E38\u9690\u853D\u7684\u5927\u95EE\u9898\u3002</p><p>\u6240\u4EE5\uFF0C\u5F88\u591A\u5927\u578B\u7684\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\u4F01\u4E1A\u90FD\u4F1A\u6267\u884C\u4E25\u683C\u7684\u7A33\u5B9A\u6027\u6D4B\u8BD5\uFF0C\u5E76\u628A\u7A33\u5B9A\u6027\u6D4B\u8BD5\u7684\u7ED3\u679C\u4F5C\u4E3A\u4EA7\u54C1\u662F\u5426\u53EF\u4EE5\u53D1\u5E03\u7684\u786C\u6027\u8981\u6C42\u3002\u6BD4\u5982\uFF0C\u6211\u66FE\u7ECF\u5DE5\u4F5C\u8FC7\u7684 HP \u8F6F\u4EF6\u7814\u53D1\u4E2D\u5FC3\uFF0C\u5B83\u6BCF\u6B21\u4EA7\u54C1\u53D1\u5E03\u524D\u90FD\u4F1A\u7531\u4E13\u95E8\u7684\u6027\u80FD\u6D4B\u8BD5\u56E2\u961F\u5B8C\u6210\u4E25\u683C\u7684\u7A33\u5B9A\u6027\u6D4B\u8BD5\uFF0C\u5E76\u4EE5\u6B64\u6765\u51B3\u5B9A\u662F\u5426\u8981\u53D1\u5E03\u8FD9\u4E2A\u4EA7\u54C1\u3002</p><p><strong>\u5E76\u53D1\u6D4B\u8BD5</strong></p><p>\u5E76\u53D1\u6D4B\u8BD5\uFF0C\u662F\u5728\u9AD8\u5E76\u53D1\u60C5\u51B5\u4E0B\u9A8C\u8BC1\u5355\u4E00\u4E1A\u52A1\u529F\u80FD\u7684\u6B63\u786E\u6027\u4EE5\u53CA\u6027\u80FD\u7684\u6D4B\u8BD5\u624B\u6BB5\u3002\u9AD8\u5E76\u53D1\u6D4B\u8BD5\u4E00\u822C\u4F7F\u7528\u601D\u8003\u65F6\u95F4\u4E3A\u96F6\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u6765\u53D1\u8D77\u5177\u6709\u201C\u96C6\u5408\u70B9\u201D\u7684\u6D4B\u8BD5\u3002</p><p>\u201C\u96C6\u5408\u70B9\u201D\u7684\u6982\u5FF5\uFF0C\u6211\u5DF2\u7ECF\u5728\u300A\u804A\u804A\u6027\u80FD\u6D4B\u8BD5\u7684\u57FA\u672C\u65B9\u6CD5\u4E0E\u5E94\u7528\u9886\u57DF\u300B\u4E2D\u89E3\u91CA\u8FC7\u4E86\u3002\u5982\u679C\u4F60\u4E0D\u6E05\u695A\u7684\u8BDD\uFF0C\u53EF\u4EE5\u518D\u56DE\u987E\u4E00\u4E0B\u8FD9\u7BC7\u6587\u7AE0\u3002\u5982\u679C\u4F60\u8FD8\u6709\u4E0D\u7406\u89E3\u7684\u5730\u65B9\uFF0C\u4E5F\u6B22\u8FCE\u548C\u6211\u7559\u8A00\u8BA8\u8BBA\u3002</p><p>\u5E76\u53D1\u6D4B\u8BD5\uFF0C\u5F80\u5F80\u88AB\u5F53\u4F5C\u529F\u80FD\u6D4B\u8BD5\u7684\u8865\u5145\uFF0C\u4E3B\u8981\u7528\u4E8E\u53D1\u73B0\u8BF8\u5982\u591A\u7EBF\u7A0B\u3001\u8D44\u6E90\u7ADE\u4E89\u3001\u8D44\u6E90\u6B7B\u9501\u4E4B\u7C7B\u7684\u9519\u8BEF\u3002\u8981\u6267\u884C\u5E76\u53D1\u6D4B\u8BD5\uFF0C\u5C31\u9700\u8981\u52A0\u5165\u201C\u96C6\u5408\u70B9\u201D\uFF0C\u6240\u4EE5\u5F80\u5F80\u9700\u8981\u4FEE\u6539\u865A\u62DF\u7528\u6237\u811A\u672C\u3002</p><p>\u52A0\u5165\u201C\u96C6\u5408\u70B9\u201D\u4E00\u822C\u6709\u4E24\u79CD\u505A\u6CD5\uFF1A</p><p>\u5728\u865A\u62DF\u7528\u6237\u811A\u672C\u7684\u5F55\u5236\u8FC7\u7A0B\u4E2D\u76F4\u63A5\u6DFB\u52A0\uFF1B</p><p>\u5728\u865A\u62DF\u7528\u6237\u811A\u672C\u4E2D\uFF0C\u901A\u8FC7\u52A0\u5165 lr_rendezvous()\u51FD\u6570\u6DFB\u52A0\u3002</p><p><strong>\u5BB9\u91CF\u89C4\u5212\u6D4B\u8BD5</strong></p><p>\u5BB9\u91CF\u89C4\u5212\u6D4B\u8BD5\uFF0C\u662F\u4E3A\u4E86\u5B8C\u6210\u5BB9\u91CF\u89C4\u5212\u800C\u8BBE\u8BA1\u6267\u884C\u7684\u6D4B\u8BD5\u3002</p><p>\u90A3\u4EC0\u4E48\u662F\u5BB9\u91CF\u89C4\u5212\u5462\uFF1F\u6240\u8C13\u5BB9\u91CF\u89C4\u5212\uFF0C\u662F\u8F6F\u4EF6\u4EA7\u54C1\u4E3A\u6EE1\u8DB3\u7528\u6237\u76EE\u6807\u8D1F\u8F7D\u800C\u8C03\u6574\u81EA\u8EAB\u751F\u4EA7\u80FD\u529B\u7684\u8FC7\u7A0B\u3002</p><p>\u6240\u4EE5\uFF0C<strong>\u5BB9\u91CF\u89C4\u5212\u7684\u4E3B\u8981\u76EE\u7684\u662F\uFF0C\u89E3\u51B3\u5F53\u7CFB\u7EDF\u8D1F\u8F7D\u5C06\u8981\u8FBE\u5230\u6781\u9650\u5904\u7406\u80FD\u529B\u65F6\uFF0C\u6211\u4EEC\u5E94\u8BE5\u5982\u4F55\u901A\u8FC7\u5782\u76F4\u6269\u5C55\uFF08\u589E\u52A0\u5355\u673A\u7684\u786C\u4EF6\u8D44\u6E90\uFF09\u548C\u6C34\u5E73\u6269\u5C55\uFF08\u589E\u52A0\u96C6\u7FA4\u4E2D\u7684\u673A\u5668\u6570\u91CF\uFF09\u589E\u52A0\u7CFB\u7EDF\u6574\u4F53\u7684\u8D1F\u8F7D\u5904\u7406\u80FD\u529B\u7684\u95EE\u9898</strong>\u3002</p><p>\u76EE\u524D\u6765\u8BB2\uFF0C\u5BB9\u91CF\u89C4\u5212\u7684\u4E3B\u8981\u65B9\u6CD5\u662F\u57FA\u4E8E\u6C34\u5E73\u6269\u5C55\u3002\u4F46\u662F\uFF0C\u5177\u4F53\u5E94\u8BE5\u589E\u52A0\u591A\u5C11\u673A\u5668\uFF0C\u4EE5\u53CA\u589E\u52A0\u540E\u7CFB\u7EDF\u7684\u8D1F\u8F7D\u5904\u7406\u80FD\u529B\u662F\u5426\u4F1A\u7EBF\u6027\u589E\u957F\uFF0C\u8FD9\u4E9B\u95EE\u9898\u90FD\u9700\u8981\u901A\u8FC7\u5BB9\u91CF\u89C4\u5212\u6D4B\u8BD5\u8FDB\u884C\u9A8C\u8BC1\u3002</p><p>\u90A3\u4E48\uFF0C\u5BB9\u91CF\u89C4\u5212\u6D4B\u8BD5\u5177\u4F53\u8981\u600E\u4E48\u505A\u5462\uFF1F</p><p>\u6211\u4EEC\u53EF\u4EE5\u4F7F\u7528\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\u4E2D\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u4EE5\u53CA\u5404\u4E2A\u4E1A\u52A1\u64CD\u4F5C\u811A\u672C\u7684\u767E\u5206\u6BD4\uFF0C\u538B\u6D4B\u5355\u673A\u90E8\u7F72\u7684\u88AB\u6D4B\u7CFB\u7EDF\u3002\u6211\u4EEC\u4F1A\u91C7\u7528\u4EBA\u5DE5\u7684\u65B9\u5F0F\u4E0D\u65AD\u589E\u52A0\u6D4B\u8BD5\u8D1F\u8F7D\u76F4\u5230\u5355\u673A\u7CFB\u7EDF\u7684\u541E\u5410\u91CF\u6307\u6807\u5230\u8FBE\u4E34\u754C\u503C\uFF0C\u7531\u6B64\u5C31\u53EF\u4EE5\u77E5\u9053\u5355\u53F0\u673A\u5668\u7684\u5904\u7406\u80FD\u529B\u3002</p><p><strong>\u7406\u8BBA\u4E0A\u8BB2\uFF0C\u6574\u4E2A\u96C6\u7FA4\u7684\u5904\u7406\u80FD\u529B\u5C06\u7B49\u4E8E\u5355\u53F0\u673A\u5668\u7684\u5904\u7406\u80FD\u529B\u4E58\u4EE5\u96C6\u7FA4\u7684\u673A\u5668\u6570\uFF0C\u4F46\u662F\u5B9E\u9645\u60C5\u51B5\u5E76\u4E0D\u662F\u8FD9\u6837</strong>\u3002\u5B9E\u9645\u7684\u96C6\u7FA4\u6574\u4F53\u5904\u7406\u80FD\u529B\u4E00\u5B9A\u5C0F\u4E8E\u8FD9\u4E2A\u503C\uFF0C\u4F46\u5177\u4F53\u5C0F\u591A\u5C11\u5C31\u662F\u8981\u9760\u5B9E\u9645\u7684\u6D4B\u8BD5\u9A8C\u8BC1\u4E86\u3002</p><p>\u7406\u60F3\u7684\u72B6\u6001\u662F\uFF0C\u96C6\u7FA4\u6574\u4F53\u7684\u5904\u7406\u80FD\u529B\u80FD\u591F\u968F\u7740\u96C6\u7FA4\u673A\u5668\u6570\u91CF\u7684\u589E\u957F\u5448\u7EBF\u6027\u589E\u957F\u3002\u4F46\u662F\uFF0C\u968F\u7740\u673A\u5668\u6570\u91CF\u7684\u4E0D\u65AD\u589E\u957F\uFF0C\u603B\u4F1A\u5728\u8FBE\u5230\u67D0\u4E2A\u4E34\u754C\u503C\u4E4B\u540E\uFF0C\u96C6\u7FA4\u7684\u6574\u4F53\u5904\u7406\u80FD\u529B\u4E0D\u518D\u7EE7\u7EED\u5448\u7EBF\u6027\u589E\u957F\u3002\u8FD9\u4E2A\u4E34\u754C\u503C\u662F\u591A\u5C11\uFF0C\u6211\u4EEC\u4E5F\u9700\u8981\u901A\u8FC7\u5BB9\u91CF\u89C4\u5212\u6D4B\u8BD5\u627E\u51FA\u6765\u4E86\u3002</p><p>\u53E6\u5916\uFF0C\u5BB9\u91CF\u89C4\u5212\u6D4B\u8BD5\u7684\u6D4B\u8BD5\u7ED3\u679C\u8FD8\u53EF\u4EE5\u88AB\u7528\u4F5C\u7CFB\u7EDF\u5BB9\u91CF\u8BBE\u8BA1\u7684\u4F9D\u636E\u3002\u6BD4\u5982\uFF0C\u4F01\u4E1A\u7EA7\u8F6F\u4EF6\u4EA7\u54C1\u7684\u76EE\u6807\u7528\u6237\u89C4\u6A21\u901A\u5E38\u662F\u53EF\u4EE5\u9884\u4F30\u7684\uFF0C\u90A3\u4E48\u6211\u4EEC\u5C31\u53EF\u4EE5\u901A\u8FC7\u8FD9\u4E9B\u9884\u4F30\u7684\u7CFB\u7EDF\u8D1F\u8F7D\u8BA1\u7B97\u51FA\u8F6F\u4EF6\u90E8\u7F72\u7684\u96C6\u7FA4\u89C4\u6A21\uFF0C\u5E76\u4E14\u53EF\u4EE5\u5728\u5177\u4F53\u5B9E\u65BD\u540E\u901A\u8FC7\u5BB9\u91CF\u6D4B\u8BD5\u7684\u65B9\u5F0F\u8FDB\u884C\u9A8C\u8BC1\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u5728\u524D\u9762\u7684\u4E24\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u5982\u4F55\u57FA\u4E8E LoadRunner \u5F00\u5C55\u6027\u80FD\u6D4B\u8BD5\uFF0C\u4F46\u662F\u5E76\u6CA1\u6709\u5177\u4F53\u53BB\u8BB2\u89E3\u8981\u5F00\u5C55\u54EA\u4E9B\u7C7B\u578B\u7684\u6027\u80FD\u6D4B\u8BD5\u3002\u6240\u4EE5\uFF0C\u4ECA\u5929\u6211\u5C31\u6311\u9009\u4E86\u6700\u91CD\u8981\u7684\u56DB\u7C7B\u6027\u80FD\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u548C\u4F60\u5206\u4EAB\u5982\u4F55\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\u5B8C\u6210\u8FD9\u4E9B\u6D4B\u8BD5\uFF0C\u786E\u4FDD\u8F6F\u4EF6\u7684\u6027\u80FD\u3002</p><p>\u6027\u80FD\u57FA\u51C6\u6D4B\u8BD5\uFF0C\u53EF\u4EE5\u4FDD\u8BC1\u65B0\u53D1\u5E03\u7CFB\u7EDF\u7684\u6574\u4F53\u6027\u80FD\u4E0D\u4F1A\u4E0B\u964D\uFF1B \u7A33\u5B9A\u6027\u6D4B\u8BD5\uFF0C\u4E3B\u8981\u901A\u8FC7\u957F\u65F6\u95F4\u6A21\u62DF\u88AB\u6D4B\u7CFB\u7EDF\u7684\u6D4B\u8BD5\u8D1F\u8F7D\uFF0C\u89C2\u5BDF\u7CFB\u7EDF\u5728\u957F\u671F\u8FD0\u884C\u8FC7\u7A0B\u662F\u5426\u5B58\u5728\u95EE\u9898\uFF1B \u5E76\u53D1\u6D4B\u8BD5\uFF0C\u5F80\u5F80\u88AB\u5F53\u4F5C\u529F\u80FD\u6D4B\u8BD5\u7684\u8865\u5145\u53BB\u53D1\u73B0\u591A\u7EBF\u7A0B\u3001\u8D44\u6E90\u7ADE\u4E89\u3001\u8D44\u6E90\u6B7B\u9501\u4E4B\u7C7B\u7684\u95EE\u9898\u3002 \u5BB9\u91CF\u89C4\u5212\u6D4B\u8BD5\uFF0C\u4E3B\u8981\u7528\u4E8E\u786E\u5B9A\u7ED9\u5B9A\u8D1F\u8F7D\u4E0B\u7684\u7CFB\u7EDF\u96C6\u7FA4\u89C4\u6A21\uFF0C\u5176\u6D4B\u8BD5\u7ED3\u679C\u53EF\u4EE5\u88AB\u7528\u4F5C\u7CFB\u7EDF\u5BB9\u91CF\u8BBE\u8BA1\u7684\u4F9D\u636E\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u6240\u5728\u4F01\u4E1A\uFF0C\u8FD8\u4F1A\u91C7\u7528\u54EA\u4E9B\u6027\u80FD\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u53C8\u662F\u5982\u4F55\u5C55\u5F00\u5177\u4F53\u7684\u6D4B\u8BD5\u5DE5\u4F5C\u7684\u5462\uFF1F</p>',55);function s(e,o){return t}var i=p(n,[["render",s],["__file","34.html.vue"]]);export{i as default};
